import React, { useState } from "react";
import "./Placement.css";

export default function Placement() {
  const user = JSON.parse(localStorage.getItem("loggedInUser"));
  const isStudent = user?.role === "Student";

  const [placements, setPlacements] = useState([
    {
      title: "Software Engineer",
      company: "InnovateTech",
      description: "Full-time role in product development.",
    },
    {
      title: "System Analyst",
      company: "SysSolutions",
      description: "Analyze systems and provide tech support.",
    },
  ]);

  const [newPlacement, setNewPlacement] = useState({
    title: "",
    company: "",
    description: "",
  });

  const [editIndex, setEditIndex] = useState(null);

  const handleChange = (e) => {
    setNewPlacement({ ...newPlacement, [e.target.name]: e.target.value });
  };

  const handleSubmit = () => {
    if (editIndex !== null) {
      const updated = [...placements];
      updated[editIndex] = newPlacement;
      setPlacements(updated);
      setEditIndex(null);
    } else {
      setPlacements([...placements, newPlacement]);
    }
    setNewPlacement({ title: "", company: "", description: "" });
  };

  const handleEdit = (index) => {
    setEditIndex(index);
    setNewPlacement(placements[index]);
  };

  const handleDelete = (index) => {
    const updated = placements.filter((_, i) => i !== index);
    setPlacements(updated);
  };

  const applyToPlacement = (item) => {
    alert(`You applied to ${item.title} at ${item.company}!`);
  };

  return (
    <div className="placement-container">
      <h2>Placement Opportunities</h2>

      <div className="placement-list">
        {placements.map((item, index) => (
          <div key={index} className="card">
            <h3>{item.title}</h3>
            <p><strong>Company:</strong> {item.company}</p>
            <p>{item.description}</p>

            {isStudent ? (
              <button onClick={() => applyToPlacement(item)} className="btn-apply">
                Apply
              </button>
            ) : (
              <div className="admin-actions">
                <button onClick={() => handleEdit(index)}>Edit</button>
                <button onClick={() => handleDelete(index)}>Delete</button>
              </div>
            )}
          </div>
        ))}
      </div>

      {!isStudent && (
        <div className="placement-form">
          <h3>{editIndex !== null ? "Edit" : "Add"} Placement</h3>
          <input
            type="text"
            name="title"
            placeholder="Title"
            value={newPlacement.title}
            onChange={handleChange}
          />
          <input
            type="text"
            name="company"
            placeholder="Company"
            value={newPlacement.company}
            onChange={handleChange}
          />
          <textarea
            name="description"
            placeholder="Description"
            value={newPlacement.description}
            onChange={handleChange}
          ></textarea>
          <button onClick={handleSubmit} className="btn-submit">
            {editIndex !== null ? "Update" : "Add"}
          </button>
        </div>
      )}
    </div>
  );
}
